#[cfg(test)]
mod tests {
    use super::*;
    use std::io::Write;

    /// transpose_dense identity: T(T(x)) == x for arbitrary rectangular
    /// shapes. Catches off-by-one errors in the row/col swap that would
    /// silently corrupt K/V/FFN-gate loads.
    #[test]
    fn transpose_dense_is_self_inverse() {
        let original = DenseTensor {
            rows: 3,
            cols: 5,
            data: (0..15).map(|i| i as f32).collect(),
        };
        let once = transpose_dense(original.clone());
        assert_eq!(once.rows, 5);
        assert_eq!(once.cols, 3);
        // Spot-check: original[1,3] (= 1*5 + 3 = 8) should land at
        // once[3,1] = 3*3 + 1 = 10.
        assert_eq!(once.data[10], 8.0);
        let twice = transpose_dense(once);
        assert_eq!(twice.rows, original.rows);
        assert_eq!(twice.cols, original.cols);
        assert_eq!(twice.data, original.data);
    }

    /// Minimal `KnotConfig` JSON used by the test fixtures. Picks small
    /// dims so a fake .knot stays under 1 KiB.
    fn fixture_config_json() -> serde_json::Value {
        serde_json::json!({
            "hidden_dim": 4,
            "num_layers": 1,
            "num_heads": 2,
            "num_kv_heads": 1,
            "head_dim": 2,
            "intermediate_size": 6,
            "vocab_size": 16,
            "rms_norm_eps": 1.0e-5,
            "rope_theta": 10000.0
        })
    }

    /// Build a fake dense `.knot` file in memory. Returns the bytes.
    ///
    /// Layout matches the production loader: after the metadata bytes,
    /// pad up to a 4-byte boundary AND insert one codec-marker byte
    /// before the tensor body. This is the same offset
    /// `loader.rs::HttpBackend::open` expects.
    ///
    ///   magic (4) || version (2) || meta_len (4) || meta_json
    ///   || pad-to-4 || codec_marker (1) || body
    ///
    /// `tensor_specs` is `(name, qtype, payload_bytes)`. Offsets are
    /// computed sequentially starting at 0 (body-relative).
    fn build_fake_knot(
        config: serde_json::Value,
        tensor_specs: &[(&str, &str, Vec<u8>)],
    ) -> Vec<u8> {
        build_fake_knot_with_meta_padding(config, tensor_specs, None)
    }

    /// Same as [`build_fake_knot`] but allows tests to inject extra
    /// trailing whitespace into the metadata JSON to force a specific
    /// `meta_len` (used by the body-origin reconciliation tests to
    /// exercise both aligned and unaligned metadata lengths).
    fn build_fake_knot_with_meta_padding(
        config: serde_json::Value,
        tensor_specs: &[(&str, &str, Vec<u8>)],
        target_meta_len: Option<usize>,
    ) -> Vec<u8> {
        // Build the tensors map with sequential body-relative offsets.
        let mut tensors_map = serde_json::Map::new();
        let mut next_offset: u64 = 0;
        let mut body = Vec::<u8>::new();
        for (name, qtype, payload) in tensor_specs {
            tensors_map.insert(
                name.to_string(),
                serde_json::json!({
                    "offset": next_offset,
                    "length": payload.len() as u64,
                    "type": qtype
                }),
            );
            body.extend_from_slice(payload);
            next_offset += payload.len() as u64;
        }
        let meta = serde_json::json!({
            "name": "fake-test-knot",
            "codec": "fp32",
            "topology": "dense",
            "config": config,
            "tensors": serde_json::Value::Object(tensors_map),
        });
        let mut meta_str = serde_json::to_string(&meta).unwrap();
        if let Some(want) = target_meta_len {
            assert!(
                want >= meta_str.len(),
                "target_meta_len {} smaller than actual meta {}",
                want,
                meta_str.len()
            );
            // Pad by appending JSON-legal whitespace BEFORE the closing
            // brace so the resulting string still parses as the same
            // object. JSON allows arbitrary whitespace inside containers.
            let pad = want - meta_str.len();
            assert!(meta_str.ends_with('}'));
            meta_str.pop(); // drop closing brace
            for _ in 0..pad {
                meta_str.push(' ');
            }
            meta_str.push('}');
            assert_eq!(meta_str.len(), want);
        }
        let meta_bytes = meta_str.as_bytes();
        let meta_len = meta_bytes.len();

        let mut out = Vec::new();
        out.extend_from_slice(b"KNOT");
        out.extend_from_slice(&[0u8, 0u8]); // version
        out.extend_from_slice(&(meta_len as u32).to_le_bytes());
        out.extend_from_slice(meta_bytes);
        // Production layout: align (10 + meta_len) up to a 4-byte
        // boundary, then drop one codec marker byte, then body.
        let aligned = (10 + meta_len + 3) & !3;
        let pad = aligned - (10 + meta_len);
        for _ in 0..pad {
            out.push(0u8);
        }
        out.push(0u8); // codec marker (value irrelevant for the reader)
        out.extend_from_slice(&body);
        out
    }

    fn write_temp(name: &str, bytes: &[u8]) -> std::path::PathBuf {
        let path =
            std::env::temp_dir().join(format!("dense_reader_{}_{}.knot", name, std::process::id()));
        let mut f = std::fs::File::create(&path).unwrap();
        f.write_all(bytes).unwrap();
        path
    }

    #[test]
    fn open_rejects_bad_magic() {
        // Build a file that is a valid length but starts with "NOPE".
        let mut bytes = Vec::new();
        bytes.extend_from_slice(b"NOPE");
        bytes.extend_from_slice(&[0u8, 0u8]);
        bytes.extend_from_slice(&0u32.to_le_bytes());
        let path = write_temp("bad_magic", &bytes);

        let result = DenseKnotReader::open(&path);
        let _ = std::fs::remove_file(&path);

        match result {
            Err(DenseReadError::KnotLoader(msg)) => {
                assert!(
                    msg.contains("not a KNOT") || msg.contains("magic"),
                    "expected magic-rejection message, got: {}",
                    msg
                );
            }
            Err(other) => panic!("expected KnotLoader(bad magic), got {:?}", other),
            Ok(_) => panic!("expected KnotLoader(bad magic), got Ok(reader)"),
        }
    }

    #[test]
    fn tensor_offsets_within_file() {
        // Two fp32 tensors, total payload 16 + 16 = 32 bytes. Verify
        // every TensorInfo's (offset, length) lies inside the file
        // body (i.e. body_origin + offset + length <= file size).
        let payload_a: Vec<u8> = (0..16).map(|i| i as u8).collect();
        let payload_b: Vec<u8> = (16..32).map(|i| i as u8).collect();
        let bytes = build_fake_knot(
            fixture_config_json(),
            &[
                ("blk.0.attn_q.weight", "fp32", payload_a.clone()),
                ("blk.0.attn_k.weight", "fp32", payload_b.clone()),
            ],
        );
        let file_size = bytes.len() as u64;
        let path = write_temp("offsets_within_file", &bytes);

        let reader = DenseKnotReader::open(&path).expect("open");
        let body_origin = reader.body_origin;
        for (name, info) in &reader.tensors {
            let abs_end = body_origin + info.offset + info.length;
            assert!(
                abs_end <= file_size,
                "tensor {} runs past EOF: body_origin={} offset={} length={} file_size={}",
                name,
                body_origin,
                info.offset,
                info.length,
                file_size
            );
        }
        drop(reader);
        let _ = std::fs::remove_file(&path);
    }

    #[test]
    fn load_tensor_dimension_check() {
        // Write an fp32 tensor whose payload is 16 bytes (4 elems), then
        // ask for it as a 4×4 = 16-element shape. That MISMATCHES, so
        // we expect DimensionMismatch.
        let payload: Vec<u8> = (0..16).map(|i| i as u8).collect(); // 4 fp32 elems
        let bytes = build_fake_knot(
            fixture_config_json(),
            &[("blk.0.attn_q.weight", "fp32", payload)],
        );
        let path = write_temp("dim_check", &bytes);

        let mut reader = DenseKnotReader::open(&path).expect("open");
        let result = reader.load_tensor("blk.0.attn_q.weight", 4, 4);
        drop(reader);
        let _ = std::fs::remove_file(&path);

        match result {
            Err(DenseReadError::DimensionMismatch {
                tensor,
                expected,
                got,
            }) => {
                assert_eq!(tensor, "blk.0.attn_q.weight");
                assert_eq!(expected, (4, 4));
                assert_eq!(got, 4); // 16 bytes / 4 = 4 fp32 elems
            }
            other => panic!("expected DimensionMismatch, got {:?}", other),
        }
    }

    #[test]
    fn unsupported_quant_returns_error() {
        // IQ4_XS (importance-quantized 4-bit, llama.cpp ggml-quants
        // imatrix-aware) is not yet implemented. Asking for it should
        // surface UnsupportedQuantType with the original (lower-cased)
        // tag so the caller can route to a future decoder.
        let payload = vec![0u8; 64];
        let bytes = build_fake_knot(
            fixture_config_json(),
            &[("blk.0.attn_q.weight", "IQ4_XS", payload)],
        );
        let path = write_temp("unsupported_quant", &bytes);

        let mut reader = DenseKnotReader::open(&path).expect("open");
        let result = reader.load_tensor("blk.0.attn_q.weight", 4, 4);
        drop(reader);
        let _ = std::fs::remove_file(&path);

        match result {
            Err(DenseReadError::UnsupportedQuantType(t)) => {
                assert_eq!(t, "iq4_xs");
            }
            other => panic!("expected UnsupportedQuantType, got {:?}", other),
        }
    }

    // Additional sanity: fp16 and fp32 round-trip a couple of well-known
    // bit patterns. Not part of the contract test list, but cheap and
    // catches the hand-rolled f16 conversion drifting.
    #[test]
    fn f16_well_known_values() {
        // 0x3c00 = 1.0; 0xc000 = -2.0; 0x0000 = 0.0; 0x7c00 = +inf
        assert_eq!(f16_bits_to_f32(0x3c00), 1.0);
        assert_eq!(f16_bits_to_f32(0xc000), -2.0);
        assert_eq!(f16_bits_to_f32(0x0000), 0.0);
        assert!(f16_bits_to_f32(0x7c00).is_infinite());
        assert!(f16_bits_to_f32(0xfc00).is_infinite() && f16_bits_to_f32(0xfc00) < 0.0);
    }

    // ─────────────────────────────────────────────────────────────────
    // Phase 3 contract tests
    // ─────────────────────────────────────────────────────────────────

    /// Production formula used by `loader.rs` (mirrored here so the
    /// tests can compute the same offset without depending on a
    /// concrete loader instance).
    fn production_body_origin(meta_len: usize) -> u64 {
        let aligned = (10 + meta_len + 3) & !3;
        (aligned + 1) as u64
    }

    /// Build a fixture with a target meta_len, open it, and verify
    /// `body_origin` plus the bytes at the body match what the
    /// production loader would compute and read.
    fn assert_body_origin_for_meta_len(meta_len: usize, label: &str) {
        // Synthesize a small fp32 payload so we can verify the body
        // round-trips through the Phase-3 reader.
        let payload: Vec<u8> = (0..16u32).flat_map(|i| (i as f32).to_le_bytes()).collect();
        assert_eq!(payload.len(), 64);
        let bytes = build_fake_knot_with_meta_padding(
            fixture_config_json(),
            &[("blk.0.attn_q.weight", "fp32", payload.clone())],
            Some(meta_len),
        );
        let path = write_temp(label, &bytes);
        let mut reader = DenseKnotReader::open(&path).expect("open");

        // 1. body_origin matches the production formula.
        assert_eq!(
            reader.body_origin,
            production_body_origin(meta_len),
            "body_origin mismatch at meta_len={}",
            meta_len
        );

        // 2. The body bytes the reader resolves match the bytes the
        //    production loader would have read at the same offset.
        let prod_origin = production_body_origin(meta_len) as usize;
        assert_eq!(
            &bytes[prod_origin..prod_origin + payload.len()],
            payload.as_slice(),
            "fixture body mismatch at meta_len={}",
            meta_len
        );

        // 3. End-to-end: load_tensor decodes the same f32 values we
        //    encoded.
        let tensor = reader
            .load_tensor("blk.0.attn_q.weight", 4, 4)
            .expect("load_tensor");
        for (i, v) in tensor.data.iter().enumerate() {
            assert_eq!(*v, i as f32, "decoded element {} mismatch", i);
        }

        drop(reader);
        let _ = std::fs::remove_file(&path);
    }

    #[test]
    fn body_origin_matches_production_loader_at_unaligned_meta_len() {
        // 10 + 401 = 411, NOT a multiple of 4 (mod 4 == 3) → 1 padding
        // byte takes us to 412, then the codec marker lifts body to 413.
        assert_body_origin_for_meta_len(401, "body_origin_unaligned");
    }

    #[test]
    fn body_origin_matches_production_loader_at_aligned_meta_len() {
        // 10 + 402 = 412 ≡ 0 mod 4 (already aligned), so no padding
        // bytes; the codec marker still lifts body to 413.
        assert_body_origin_for_meta_len(402, "body_origin_aligned");
    }

    /// Synthesize a single Q4_0 block by hand and verify the
    /// dequantizer recovers values within `scale * 0.5` of the
    /// reference (the per-nibble round-off bound of a 4-bit quant).
    #[test]
    fn dequantize_q4_0_round_trip_within_scale_error() {
        // scale = 0.25 (fp16 0x3400). Choose nibbles spanning the full
        // [0, 15] range so we hit both halves of the per-byte split.
        let scale_f32 = 0.25_f32;
        let scale_bits: u16 = 0x3400; // 0 01101 0000000000 = 0.25
                                      // Sanity: round-trip through our converter.
        assert!((f16_bits_to_f32(scale_bits) - scale_f32).abs() < 1e-7);

        // Build a 32-element block: nibble[i] = i & 0xf (for i in 0..32).
        // Element i (i<16) reads low nibble of byte i;
        // element i+16 reads high nibble of byte i.
        let mut block = Vec::with_capacity(18);
        block.extend_from_slice(&scale_bits.to_le_bytes());
        for i in 0..16u8 {
            let lo = i & 0xf; // 0..15 in some order
            let hi = (i + 8) & 0xf; // distinct from lo
            block.push((hi << 4) | lo);
        }

        let mut out = vec![0.0f32; 32];
        dequantize_q4_0(&block, &mut out);

        // Expected: low element i = scale * (lo - 8); high element i+16 = scale * (hi - 8).
        for i in 0..16 {
            let lo_nib = (i as i32) & 0xf;
            let hi_nib = ((i as i32) + 8) & 0xf;
            let want_lo = scale_f32 * (lo_nib - 8) as f32;
            let want_hi = scale_f32 * (hi_nib - 8) as f32;
            assert!(
                (out[i] - want_lo).abs() <= scale_f32 * 0.5,
                "low nibble {}: got {}, want {} (tol {})",
                i,
                out[i],
                want_lo,
                scale_f32 * 0.5
            );
            assert!(
                (out[i + 16] - want_hi).abs() <= scale_f32 * 0.5,
                "high nibble {}: got {}, want {} (tol {})",
                i,
                out[i + 16],
                want_hi,
                scale_f32 * 0.5
            );
        }
    }

    /// Synthesize a single Q8_0 block by hand and verify
    /// `crate::math::dequantize_q8_0_row` recovers values within
    /// `scale * 0.5` of the reference. Block layout: 1 fp16 scale +
    /// 32 i8 codes = 34 bytes.
    #[test]
    fn dequantize_q8_0_round_trip_within_scale_error() {
        let scale_f32 = 0.125_f32;
        let scale_bits: u16 = 0x3000; // 0 01100 0000000000 = 0.125
        assert!((f16_bits_to_f32(scale_bits) - scale_f32).abs() < 1e-7);

        let mut block = Vec::with_capacity(34);
        block.extend_from_slice(&scale_bits.to_le_bytes());
        // Codes -16..16 covers most of the i8 range without overflowing.
        for i in 0..32i8 {
            let code: i8 = i - 16;
            block.push(code as u8);
        }

        let mut out = vec![0.0f32; 32];
        crate::math::dequantize_q8_0_row(&mut out, &block, 0, 32);

        for i in 0..32 {
            let code = (i as i32) - 16;
            let want = scale_f32 * code as f32;
            assert!(
                (out[i] - want).abs() <= scale_f32 * 0.5,
                "Q8_0 element {}: got {}, want {}",
                i,
                out[i],
                want
            );
        }
    }

    /// Smoke: routing a Q4_0 payload through `load_tensor` returns a
    /// tensor whose element count matches the requested shape. The
    /// per-element correctness is exercised by
    /// `dequantize_q4_0_round_trip_within_scale_error`; this just
    /// verifies the dispatcher wires up.
    #[test]
    fn load_tensor_q4_0_dispatch_smoke() {
        // 1 block = 18 bytes = 32 elements. Shape it as 1 row × 32 cols.
        let scale_bits: u16 = 0x3400; // 0.25
        let mut block = Vec::with_capacity(18);
        block.extend_from_slice(&scale_bits.to_le_bytes());
        for _ in 0..16 {
            block.push(0x88); // hi=8, lo=8 → both dequantize to 0.0
        }
        let bytes = build_fake_knot(
            fixture_config_json(),
            &[("blk.0.attn_q.weight", "q4_0", block)],
        );
        let path = write_temp("q4_0_smoke", &bytes);
        let mut reader = DenseKnotReader::open(&path).expect("open");
        let tensor = reader
            .load_tensor("blk.0.attn_q.weight", 1, 32)
            .expect("load_tensor q4_0");
        drop(reader);
        let _ = std::fs::remove_file(&path);
        assert_eq!(tensor.data.len(), 32);
        // Both nibbles are 8, so the dequantized values are
        // `scale * (8 - 8) == 0.0` for every element.
        for v in &tensor.data {
            assert_eq!(*v, 0.0);
        }
    }
}
